    'ap_meta_title'  => ['fr'=>'À Propos — Michel Richard, Chauffeur VTC Carcassonne | AUDE VTC',
                         'en'=>'About — Michel Richard, VTC Chauffeur in Carcassonne | AUDE VTC',
                         'de'=>'Über uns — Michel Richard, VTC-Fahrer in Carcassonne | AUDE VTC'],
    'ap_meta_desc'   => ['fr'=>'Michel Richard, chauffeur privé VTC expert de l\'Occitanie. Trilingue FR/EN/DE, 5 ans d\'expérience dans le tourisme régional, Mercedes break hybride.',
                         'en'=>'Michel Richard, private VTC chauffeur and Occitanie expert. Trilingual FR/EN/DE, 5 years in regional tourism, hybrid Mercedes estate.',
                         'de'=>'Michel Richard, privater VTC-Fahrer und Okzitanien-Experte. Dreisprachig FR/EN/DE, 5 Jahre Erfahrung im regionalen Tourismus, Hybrid-Mercedes.'],

    'ap_hero_eyebrow'=> ['fr'=>'Qui sommes-nous','en'=>'Who we are','de'=>'Wer wir sind'],
    'ap_hero_h1'     => ['fr'=>'À Propos','en'=>'About','de'=>'Über'],
    'ap_hero_h1_em'  => ['fr'=>'d\'AUDE VTC','en'=>'AUDE VTC','de'=>'AUDE VTC'],
    'ap_hero_lead'   => ['fr'=>'Derrière AUDE VTC, un homme, une passion : vous faire découvrir l\'Occitanie dans les meilleures conditions.',
                         'en'=>'Behind AUDE VTC, one man and one passion: showing you Occitanie in the best possible conditions.',
                         'de'=>'Hinter AUDE VTC stehen ein Mann und eine Leidenschaft: Ihnen Okzitanien unter besten Bedingungen zu zeigen.'],

    'ap_port_eyebrow'=> ['fr'=>'Michel Richard','en'=>'Michel Richard','de'=>'Michel Richard'],
    'ap_port_title'  => ['fr'=>'Votre chauffeur,','en'=>'Your chauffeur,','de'=>'Ihr Fahrer,'],
    'ap_port_title_em'=>['fr'=>'votre guide','en'=>'your guide','de'=>'Ihr Reiseführer'],
    'ap_port_p1'     => ['fr'=>'Passionné par sa région depuis toujours, Michel Richard a choisi de faire du transport privé une expérience à part entière. Avant de créer AUDE VTC, il a travaillé plusieurs années dans le secteur du tourisme occitan — ce qui lui confère une connaissance intime des lieux, des vignobles, de l\'histoire cathare et des chemins de traverse.',
                         'en'=>'A lifelong enthusiast of his region, Michel Richard chose to turn private transport into an experience in its own right. Before founding AUDE VTC, he spent several years in Occitanie\'s tourism sector — giving him an intimate knowledge of its sights, vineyards, Cathar history and hidden back roads.',
                         'de'=>'Seit jeher seiner Region verbunden, hat Michel Richard den Privattransport zu einem echten Erlebnis gemacht. Vor der Gründung von AUDE VTC arbeitete er mehrere Jahre im okzitanischen Tourismus — daher kennt er die Orte, Weinberge, die Geschichte der Katharer und die verborgenen Wege ganz genau.'],
    'ap_port_p2'     => ['fr'=>'Trilingue français, anglais et allemand, il accueille aussi bien les voyageurs locaux que les touristes internationaux, avec la même attention portée à chaque trajet : ponctualité, discrétion, conversation — ou silence, si c\'est ce dont vous avez besoin.',
                         'en'=>'Trilingual in French, English and German, he welcomes local travellers and international visitors alike, with the same care on every trip: punctuality, discretion, conversation — or silence, if that is what you need.',
                         'de'=>'Dreisprachig in Französisch, Englisch und Deutsch empfängt er einheimische Reisende ebenso wie internationale Gäste — mit derselben Sorgfalt bei jeder Fahrt: Pünktlichkeit, Diskretion, Gespräch — oder Stille, wenn Sie das wünschen.'],

